import React, { useState, useEffect } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import { motion } from "framer-motion";
import {
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
} from "../components/ui/card";
import { Button } from "../components/ui/button";
import { Input } from "../components/ui/input";
import { authService, User } from "../services/api";
import api from "../services/api";

type ApplianceCategory = "Fan" | "Bulb" | "AC" | "Geyser" | "TV";

type Appliance = {
  id: string;
  name: string;
  category: ApplianceCategory;
  watts: number;
};

type ApplianceDraft = {
  id: string;
  name: string;
  category: ApplianceCategory | "";
  watts: string;
};

type Room = {
  id: string;
  name: string;
  appliances: Appliance[];
  drafts: ApplianceDraft[];
};

const categories: ApplianceCategory[] = ["Fan", "Bulb", "AC", "Geyser", "TV"];

const fadeScale = {
  initial: { opacity: 0, scale: 0.97, y: 8 },
  animate: { opacity: 1, scale: 1, y: 0 },
};

const AddRoom: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [rooms, setRooms] = useState<Room[]>([]);
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  useEffect(() => {
    const fetchUser = async () => {
      try {
        const token = localStorage.getItem("access_token");
        if (!token) {
          navigate("/login");
          return;
        }

        const userData = await authService.getCurrentUser();
        setUser(userData);
      } catch (error) {
        console.error("Failed to fetch user:", error);
        navigate("/login");
      } finally {
        setLoading(false);
      }
    };

    fetchUser();
  }, [navigate]);

  const handleLogout = () => {
    authService.logout();
    navigate("/login");
  };

  const handleBack = () => {
    navigate("/dashboard");
  };

  // Create a new room when query param add=1 exists, then clear it
  useEffect(() => {
    if (searchParams.get("add") === "1") {
      addRoom();
      const next = new URLSearchParams(searchParams);
      next.delete("add");
      setSearchParams(next, { replace: true });
    }
  }, [searchParams, setSearchParams]);

  const addRoom = () => {
    const newRoom: Room = {
      id: crypto.randomUUID(),
      name: "",
      appliances: [],
      drafts: [
        { id: crypto.randomUUID(), name: "", category: "", watts: "" },
      ],
    };
    setRooms((prev) => [...prev, newRoom]);
  };

  const saveRoomToDatabase = async (room: Room) => {
    try {
      if (!room.name.trim()) {
        alert("Please enter a room name before saving.");
        return;
      }

      // Create room in database
      const roomResponse = await api.post('/energy/rooms', {
        name: room.name,
      });

      const roomId = roomResponse.data.id;

      // Create appliances for this room
      for (const appliance of room.appliances) {
        await api.post('/appliances', {
          name: appliance.name,
          category: appliance.category.toLowerCase(),
          wattage: appliance.watts,
          room_id: roomId,
        });
      }

      alert("Room and appliances saved successfully!");

      // Remove the room from local state after saving
      setRooms((prev) => prev.filter((r) => r.id !== room.id));

    } catch (error) {
      console.error("Failed to save room:", error);
      alert("Failed to save room. Please try again.");
    }
  };

  const processImageWithGemini = async (file: File): Promise<{name: string, watts: number}> => {
    try {
      // In a real implementation, you would:
      // 1. Upload the image to your backend
      // 2. Backend calls Google Gemini Vision API
      // 3. Extract appliance name and wattage from the energy label

      // For now, return mock data
      await new Promise(resolve => setTimeout(resolve, 2000)); // Simulate API call

      return {
        name: "Detected Appliance Name",
        watts: 75
      };
    } catch (error) {
      console.error("Failed to process image:", error);
      throw error;
    }
  };

  const handleImageUpload = async (roomId: string, draftId: string, file: File) => {
    try {
      const processedData = await processImageWithGemini(file);

      // Update the draft with processed data
      setRooms((prev) =>
        prev.map((r) =>
          r.id === roomId
            ? {
                ...r,
                drafts: r.drafts.map((d) =>
                  d.id === draftId 
                    ? { 
                        ...d, 
                        name: processedData.name,
                        watts: processedData.watts.toString()
                      } 
                    : d
                ),
              }
            : r
        )
      );
    } catch (error) {
      alert("Failed to process image. Please try manual entry.");
    }
  };

  const updateRoomName = (roomId: string, name: string) => {
    setRooms((prev) =>
      prev.map((r) => (r.id === roomId ? { ...r, name } : r))
    );
  };

  const addDraft = (roomId: string) => {
    setRooms((prev) =>
      prev.map((r) =>
        r.id === roomId
          ? {
              ...r,
              drafts: [
                ...r.drafts,
                { id: crypto.randomUUID(), name: "", category: "", watts: "" },
              ],
            }
          : r
      )
    );
  };

  const updateDraft = (
    roomId: string,
    draftId: string,
    field: keyof Omit<ApplianceDraft, "id">,
    value: string
  ) => {
    setRooms((prev) =>
      prev.map((r) =>
        r.id === roomId
          ? {
              ...r,
              drafts: r.drafts.map((d) =>
                d.id === draftId ? { ...d, [field]: value } : d
              ),
            }
          : r
      )
    );
  };

  const saveDraft = (roomId: string, draftId: string) => {
    setRooms((prev) =>
      prev.map((r) => {
        if (r.id !== roomId) return r;
        const draft = r.drafts.find((d) => d.id === draftId);
        if (!draft || !draft.name || !draft.category || !draft.watts) return r;
        const wattsNum = Number(draft.watts);
        if (Number.isNaN(wattsNum)) return r;
        const newAppliance: Appliance = {
          id: crypto.randomUUID(),
          name: draft.name,
          category: draft.category as ApplianceCategory,
          watts: wattsNum,
        };
        return {
          ...r,
          appliances: [...r.appliances, newAppliance],
          drafts: r.drafts.filter((d) => d.id !== draftId),
        };
      })
    );
  };

  const RoomCard: React.FC<{ room: Room }> = ({ room }) => {
    return (
      <motion.div
        initial={fadeScale.initial}
        animate={fadeScale.animate}
        transition={{ duration: 0.25 }}
      >
        <Card className="bg-white/80 backdrop-blur-lg border-gray-200 shadow-xl">
          <CardHeader>
            <div className="flex items-center justify-between gap-3">
              <div className="flex-1">
                {room.name ? (
                  <CardTitle>{room.name}</CardTitle>
                ) : (
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                      Room Name
                    </label>
                    <Input
                      placeholder="e.g., Living Room"
                      value={room.name}
                      onChange={(e) => updateRoomName(room.id, e.target.value)}
                      className="bg-white border-gray-300 focus:border-blue-500 focus:ring-blue-500"
                    />
                  </div>
                )}
              </div>
            </div>
            {!room.name && (
              <p className="text-sm text-gray-500 mt-2">
                Enter a name to set the card title
              </p>
            )}
          </CardHeader>
          <CardContent>
            {/* Saved appliances */}
            <div className="space-y-2 mb-4">
              {room.appliances.map((a) => (
                <div
                  key={a.id}
                  className="flex items-center justify-between rounded-md border border-gray-200 bg-white px-3 py-2"
                >
                  <span className="font-medium text-gray-800">
                    {a.category} – {a.watts}W
                  </span>
                  <span className="text-sm text-gray-600">{a.name}</span>
                </div>
              ))}
              {room.appliances.length === 0 && (
                <p className="text-sm text-gray-500">No appliances saved yet.</p>
              )}
            </div>

            {/* Draft forms */}
            <div className="space-y-4">
              {room.drafts.map((d) => (
                <div
                  key={d.id}
                  className="rounded-lg border border-gray-200 p-4 bg-white space-y-3"
                >
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">
                        Appliance Name
                      </label>
                      <div className="flex items-center gap-2">
                        <Input
                          placeholder="e.g., Ceiling Fan"
                          value={d.name}
                          onChange={(e) =>
                            updateDraft(room.id, d.id, "name", e.target.value)
                          }
                          className="bg-white border-gray-300 focus:border-blue-500 focus:ring-blue-500"
                        />
                        <label className="relative cursor-pointer">
                          <Button
                            type="button"
                            variant="outline"
                            className="whitespace-nowrap hover:bg-blue-50"
                            asChild
                          >
                            <span>
                              <span className="mr-1">📷</span>
                              Upload Label
                            </span>
                          </Button>
                          <input
                            type="file"
                            accept="image/*"
                            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                            onChange={(e) => {
                              const file = e.target.files?.[0];
                              if (file) {
                                handleImageUpload(room.id, d.id, file);
                              }
                            }}
                          />
                        </label>
                      </div>
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">
                        Appliance Category
                      </label>
                      <select
                        value={d.category}
                        onChange={(e) =>
                          updateDraft(
                            room.id,
                            d.id,
                            "category",
                            e.target.value
                          )
                        }
                        className="w-full rounded-md border border-gray-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                      >
                        <option value="">Select a category</option>
                        {categories.map((c) => (
                          <option key={c} value={c}>
                            {c}
                          </option>
                        ))}
                      </select>
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">
                        Power Consumed (Watts)
                      </label>
                      <Input
                        type="number"
                        placeholder="e.g., 80"
                        value={d.watts}
                        onChange={(e) =>
                          updateDraft(room.id, d.id, "watts", e.target.value)
                        }
                        className="bg-white border-gray-300 focus:border-blue-500 focus:ring-blue-500"
                      />
                    </div>
                  </div>
                  <div className="flex justify-end gap-2">
                    <Button
                      type="button"
                      className="bg-green-100 text-green-700 hover:bg-green-200 border border-green-200"
                      variant="outline"
                      onClick={() => saveDraft(room.id, d.id)}
                    >
                      Add to Room
                    </Button>
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-4 flex justify-between items-center">
              <Button
                type="button"
                variant="outline"
                className="bg-blue-100 text-blue-700 hover:bg-blue-200 border-blue-200"
                onClick={() => addDraft(room.id)}
              >
                + Add Appliance
              </Button>

              {room.appliances.length > 0 && (
                <Button
                  type="button"
                  className="bg-green-600 text-white hover:bg-green-700"
                  onClick={() => saveRoomToDatabase(room)}
                >
                  💾 Save Room to Database
                </Button>
              )}
            </div>
          </CardContent>
        </Card>
      </motion.div>
    );
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-muted-foreground">Loading...</p>
        </div>
      </div>
    );
  }

  if (!user) return null;

  return (
    <div className="min-h-screen bg-gradient-to-br from-green-50 via-blue-50 to-indigo-100 relative overflow-hidden">
      {/* Animated Background */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute -top-4 -left-4 w-72 h-72 bg-green-200 rounded-full mix-blend-multiply filter blur-xl opacity-30 animate-pulse"></div>
        <div className="absolute top-1/4 -right-4 w-72 h-72 bg-blue-200 rounded-full mix-blend-multiply filter blur-xl opacity-30 animate-pulse animation-delay-2000"></div>
        <div className="absolute -bottom-8 left-1/3 w-72 h-72 bg-indigo-200 rounded-full mix-blend-multiply filter blur-xl opacity-30 animate-pulse animation-delay-4000"></div>
      </div>

      {/* Navigation */}
      <nav className="bg-white/90 backdrop-blur-md shadow-lg border-b border-green-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div 
              className="flex items-center space-x-3 cursor-pointer hover:opacity-80 transition-opacity"
              onClick={() => navigate('/dashboard')}
            >
              <div className="w-8 h-8 bg-gradient-to-br from-green-500 to-blue-600 rounded-lg flex items-center justify-center">
                <span className="text-white font-bold text-lg">⚡</span>
              </div>
              <h1 className="text-2xl font-bold bg-gradient-to-r from-green-600 to-blue-600 bg-clip-text text-transparent">
                WattWise
              </h1>
            </div>
            <div className="flex items-center space-x-4">
              <span className="text-sm text-gray-700 font-medium">
                Welcome, {user.username}
              </span>
              <Button
                variant="outline"
                onClick={handleBack}
                className="border-blue-200 text-blue-700 hover:bg-blue-50"
              >
                Back to Dashboard
              </Button>
              <Button
                variant="outline"
                onClick={handleLogout}
                className="border-green-200 text-green-700 hover:bg-green-50"
              >
                Logout
              </Button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
        <div className="px-4 py-6 sm:px-0 space-y-6">
          {/* Page Header */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
          >
            <Card className="bg-gradient-to-br from-white/80 to-green-50 backdrop-blur-lg border-green-200 shadow-xl">
              <CardHeader>
                <CardTitle className="text-3xl font-bold bg-gradient-to-r from-green-600 to-blue-600 bg-clip-text text-transparent">
                  Add Room & Appliances
                </CardTitle>
                <CardDescription className="text-lg text-gray-600">
                  Choose how you want to add your appliances to start tracking energy consumption
                </CardDescription>
              </CardHeader>
            </Card>
          </motion.div>

          {/* Rooms Section */}
          <div className="space-y-6">
            {rooms.map((room) => (
              <RoomCard key={room.id} room={room} />
            ))}
            <div className="flex justify-center">
              <motion.div initial={fadeScale.initial} animate={fadeScale.animate}>
                <Button
                  variant="outline"
                  onClick={addRoom}
                  className="px-6 bg-green-100 text-green-700 hover:bg-green-200 border-green-200"
                >
                  + Add Room
                </Button>
              </motion.div>
            </div>
          </div>

          {/* Additional Info Card */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.6 }}
          >
            <Card className="bg-gradient-to-br from-white/80 to-blue-50 backdrop-blur-lg border-blue-200 shadow-xl">
              <CardHeader>
                <CardTitle className="text-2xl font-bold bg-gradient-to-r from-green-600 to-blue-600 bg-clip-text text-transparent">
                  Getting Started Tips
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-4">
                    <div className="flex items-start space-x-3">
                      <div className="w-8 h-8 bg-gradient-to-br from-green-400 to-blue-500 rounded-full flex items-center justify-center flex-shrink-0 mt-1">
                        <span className="text-white font-bold text-sm">1</span>
                      </div>
                      <div>
                        <p className="font-bold text-gray-900">Manual Entry</p>
